    if (theme === "planos" && hasAnyTerm(normalizedQuestion, ["empresa", "plano empresa"])) {
      const planAnswer = getGuidedStepResponse("plano empresa");
      planAnswer.sessionTheme = "planos";
      planAnswer.sessionIntent = "continuidade";
      return planAnswer;
    }

