  function normalizeEloCoreProjectName_(name) {
    let clean = sanitizeUserText(name || "").replace(/^[\s:,-]+|[.!?;:,]+$/g, "").trim();
    clean = clean.replace(/^(?:o|a|um|uma)\s+/i, "");
    if (!clean || /^(um|uma|o|a|novo projeto|outro projeto)$/i.test(clean)) return "";
    if (/^elo core$/i.test(clean)) return "ELO Core";
    return clean.slice(0, 120);
  }

  function readEloCoreProjectMemories_() {
    try {
      const parsed = JSON.parse(window.localStorage.getItem(ELO_CORE_PROJECT_MEMORY_STORAGE_KEY) || "[]");
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }

  function writeEloCoreProjectMemories_(projects) {
    const payload = JSON.stringify((Array.isArray(projects) ? projects : []).slice(0, 20));
    try { window.localStorage.setItem(ELO_CORE_PROJECT_MEMORY_STORAGE_KEY, payload); } catch (error) {}
  }

  function getActiveEloCoreProjectMemory_() {
    return readEloCoreProjectMemories_().find(function (project) { return project && project.is_active !== false && project.project_name; }) || null;
  }

  function formatEloCoreProjectMemoryValue_(project) {
    return JSON.stringify({
      project_name: project.project_name || "",
      current_goal: project.current_goal || "",
      last_completed_task: project.last_completed_task || "",
      pending_task: project.pending_task || "",
      decisions: Array.isArray(project.decisions) ? project.decisions : [],
      updated_at: project.updated_at || new Date().toISOString(),
      is_active: project.is_active !== false
    });
  }

  function cacheEloCoreProjectMemory_(project) {
    if (!project || !project.project_name) return null;
    const nowValue = new Date().toISOString();
    const next = Object.assign({
      id: "elo_core_project_" + normalizeText(project.project_name).replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "") || "current",
      category: ELO_CORE_PROJECT_MEMORY_CATEGORY,
      memory_key: ELO_CORE_PROJECT_MEMORY_KEY,
      current_goal: "",
      last_completed_task: "",
      pending_task: "",
      decisions: [],
      is_active: true,
      created_at: nowValue
    }, project || {}, { updated_at: nowValue, is_active: project.is_active !== false });
    next.decisions = (Array.isArray(next.decisions) ? next.decisions : []).map(sanitizeUserText).filter(Boolean).filter(function (item, index, list) { return list.indexOf(item) === index; }).slice(0, 20);
    next.memory_value = formatEloCoreProjectMemoryValue_(next);
    const projects = readEloCoreProjectMemories_().map(function (item) {
      if (!item || item.id === next.id || (item.project_name && normalizeText(item.project_name) === normalizeText(next.project_name))) return Object.assign({}, item || {}, next);
      return Object.assign({}, item, { is_active: false });
    });
    if (!projects.some(function (item) { return item && item.id === next.id; })) projects.unshift(next);
    writeEloCoreProjectMemories_(projects);
    cacheEloCoreMemory_({ id: next.id, category: ELO_CORE_PROJECT_MEMORY_CATEGORY, memory_key: ELO_CORE_PROJECT_MEMORY_KEY, memory_value: next.memory_value, confidence: 0.94, is_active: next.is_active, updated_at: next.updated_at });
    return next;
  }

  function persistEloCoreProjectMemory_(project) {
    if (!project || !project.project_name || typeof fetch !== "function") return Promise.resolve(false);
    return eloCoreFetch_("/api/elo/memories", {
      method: "POST",
      body: JSON.stringify(Object.assign({}, getEloCoreIdentity_(), {
        category: ELO_CORE_PROJECT_MEMORY_CATEGORY,
        memory_key: ELO_CORE_PROJECT_MEMORY_KEY,
        memory_value: formatEloCoreProjectMemoryValue_(project),
        confidence: 0.94
      }))
    }).then(function (data) {
      if (data && data.memory) cacheEloCoreMemory_(data.memory);
      return true;
    }).catch(function () { return false; });
  }

  function saveEloCoreProjectMemory_(project) {
    const saved = cacheEloCoreProjectMemory_(project);
    if (saved) persistEloCoreProjectMemory_(saved);
    return saved;
  }

  function deactivateActiveEloCoreProject_() {
    const projects = readEloCoreProjectMemories_().map(function (item) { return Object.assign({}, item, { is_active: false, updated_at: new Date().toISOString() }); });
    writeEloCoreProjectMemories_(projects);
  }

  function detectEloCoreProjectMemoryIntent_(message) {
    const raw = sanitizeUserText(message || "");
    const text = normalizeText(raw);
    if (!raw) return null;
    if (/^mudar\s+de\s+projeto[.!?]*$/i.test(raw)) return { type: "switch" };
    if (/^(continuar|continue|onde\s+paramos)[.!?]*$/i.test(raw) || hasAnyTerm(text, ["onde paramos"])) return { type: "continue" };
    let match = raw.match(/^(?:pr[oĂł]xima\s+tarefa\s+(?:e|Ă©)|agora\s+vamos\s+fazer)\s+([\s\S]+)$/i);
    if (match) return { type: "update", pending: sanitizeUserText(match[1]).replace(/[.!?]+$/g, "") };
    if (hasAnyTerm(text, ["o que decidimos", "decisoes", "decisĂ”es", "decidimos ontem"])) return { type: "query", field: "decisions" };
    if (hasAnyTerm(text, ["qual e a proxima tarefa", "qual Ă© a prĂłxima tarefa", "qual proxima tarefa", "o que falta", "proxima tarefa", "prĂłxima tarefa"])) return { type: "query", field: "pending_task" };

    match = raw.match(/^(?:estamos\s+desenvolvendo|este\s+projeto\s+(?:e|Ă©)|nosso\s+projeto\s+(?:e|Ă©)|quero\s+criar|o\s+projeto\s+chama)\s+([\s\S]+)$/i);
    if (match) return { type: "save", project_name: normalizeEloCoreProjectName_(match[1]) };

    match = raw.match(/^(?:conclu[iĂ­]mos|terminamos|finalizamos)\s+([\s\S]+)$/i);
    if (match) return { type: "update", completed: sanitizeUserText(match[1]).replace(/[.!?]+$/g, "") };

    match = raw.match(/^(?:pr[oĂł]xima\s+tarefa\s+(?:e|Ă©)|agora\s+vamos\s+fazer)\s+([\s\S]+)$/i);
    if (match) return { type: "update", pending: sanitizeUserText(match[1]).replace(/[.!?]+$/g, "") };

    match = raw.match(/^(?:decidimos\s+que|ficou\s+decidido\s+que|decis[aĂŁ]o\s*[:,-]?)\s+([\s\S]+)$/i);
    if (match) return { type: "update", decision: sanitizeUserText(match[1]).replace(/[.!?]+$/g, "") };
    return null;
  }

  function formatEloCoreProjectTask_(task) {
    const clean = sanitizeUserText(task || "").replace(/[.!?]+$/g, "");
    if (!clean) return "";
    return clean.charAt(0).toUpperCase() + clean.slice(1) + ".";
  }

  function buildEloCoreProjectResume_(project) {
    if (!project) return "Ainda nĂŁo tenho um projeto ativo salvo.";
    const lines = ["Lembro que estamos trabalhando no " + project.project_name + "."];
    if (project.last_completed_task) lines.push("", "Ăltima tarefa concluĂ­da:", formatEloCoreProjectTask_(project.last_completed_task));
    if (project.pending_task) lines.push("", "PrĂłxima tarefa:", formatEloCoreProjectTask_(project.pending_task));
    if (Array.isArray(project.decisions) && project.decisions.length) lines.push("", "DecisĂ”es:", project.decisions.map(function (item) { return "- " + item; }).join("\n"));
    return lines.join("\n");
  }

  function buildEloCoreProjectMemoryAnswer_(message) {
    const intent = detectEloCoreProjectMemoryIntent_(message);
    if (!intent) return null;
    if (intent.type === "switch") {
      deactivateActiveEloCoreProject_();
      return { shortAnswer: "Qual projeto deseja iniciar?", fullAnswer: "Qual projeto deseja iniciar?", nextAction: "Diga: O projeto chama ...", canSave: false, sessionTheme: "projeto", sessionIntent: "project_memory_update" };
    }
    let project = getActiveEloCoreProjectMemory_();
    if (intent.type === "save" && intent.project_name) {
      project = saveEloCoreProjectMemory_({ project_name: intent.project_name, current_goal: "Desenvolver " + intent.project_name + ".", last_completed_task: /elo\s+core/i.test(intent.project_name) ? "Abertura automĂĄtica das ferramentas" : "", pending_task: /elo\s+core/i.test(intent.project_name) ? "Implementar memĂłria de projeto" : "", decisions: [] });
      const answer = "Certo. Vou lembrar que estamos trabalhando no " + project.project_name + ".";
      return { shortAnswer: answer, fullAnswer: answer, nextAction: "Diga Continuar quando quiser retomar.", canSave: false, sessionTheme: "projeto", sessionIntent: "project_memory_save" };
    }
    if (!project) {
      const answer = "Ainda nĂŁo tenho um projeto ativo salvo.";
      return { shortAnswer: answer, fullAnswer: answer, nextAction: "Diga: Estamos desenvolvendo o ELO Core.", canSave: false, sessionTheme: "projeto", sessionIntent: intent.type === "continue" ? "project_memory_continue" : "project_memory_query" };
    }
    if (intent.type === "update") {
      const decisions = Array.isArray(project.decisions) ? project.decisions.slice() : [];
      if (intent.decision && decisions.indexOf(intent.decision) < 0) decisions.push(intent.decision);
      project = saveEloCoreProjectMemory_(Object.assign({}, project, {
        last_completed_task: intent.completed ? intent.completed : project.last_completed_task,
        pending_task: intent.pending ? intent.pending : (intent.completed && normalizeText(project.pending_task) === normalizeText(intent.completed) ? "" : project.pending_task),
        decisions: decisions
      }));
      const answer = intent.completed ? "Entendido. Atualizei a Ășltima tarefa concluĂ­da do projeto." : "Entendido. Atualizei a memĂłria do projeto.";
      return { shortAnswer: answer, fullAnswer: buildEloCoreProjectResume_(project), nextAction: "Diga Continuar para retomar daqui.", canSave: false, sessionTheme: "projeto", sessionIntent: "project_memory_update" };
    }
    if (intent.type === "continue") {
      const answer = buildEloCoreProjectResume_(project);
      return { shortAnswer: answer, fullAnswer: answer, nextAction: project.pending_task || "Defina a prĂłxima tarefa.", canSave: false, sessionTheme: "projeto", sessionIntent: "project_memory_continue" };
    }
    if (intent.type === "query" && intent.field === "decisions") {
      const answer = project.decisions && project.decisions.length ? "Decidimos:\n" + project.decisions.map(function (item) { return "- " + item; }).join("\n") : "NĂŁo tenho decisĂ”es registradas para este projeto.";
      return { shortAnswer: answer, fullAnswer: answer, nextAction: "Quando houver uma decisĂŁo, diga: Decidimos que ...", canSave: false, sessionTheme: "projeto", sessionIntent: "project_memory_query" };
    }
    if (intent.type === "query" && intent.field === "pending_task") {
      const answer = project.pending_task ? "A prĂłxima tarefa Ă©: " + formatEloCoreProjectTask_(project.pending_task) : "NĂŁo hĂĄ prĂłxima tarefa registrada para este projeto.";
      return { shortAnswer: answer, fullAnswer: answer, nextAction: "VocĂȘ pode definir dizendo: PrĂłxima tarefa Ă© ...", canSave: false, sessionTheme: "projeto", sessionIntent: "project_memory_query" };
    }
    return null;
  }
  function buildEloCoreUserNameMemoryAnswer_(message) {
    const intent = detectEloCoreUserNameMemoryIntent_(message);
    if (!intent || intent.type === "invalid") return null;
    if (intent.type === "query") {
      const name = getCanonicalEloCoreUserName_();
      if (!name) {
        return {
          shortAnswer: "Ainda nĂŁo sei o seu nome.",
          fullAnswer: "Ainda nĂŁo tenho um nome salvo para vocĂȘ.",
          nextAction: "Se quiser, diga: Meu nome Ă© Ăcaro Amaral. Guarde isso.",
          canSave: false,
          sessionTheme: "perfil",
          sessionIntent: "user_name_memory"
        };
      }
      const answer = intent.mode === "identity" ? "Sim. VocĂȘ Ă© " + name + "." : "Seu nome Ă© " + name + ".";
      return {
        shortAnswer: answer,
        fullAnswer: answer,
        nextAction: "",
        canSave: false,
        sessionTheme: "perfil",
        sessionIntent: "user_name_memory"
      };
    }
    if (intent.type === "save" && intent.name) {
      const savedName = saveEloCoreCanonicalName_(intent.name);
      if (!savedName) return null;
      const answer = intent.correction
        ? "Entendido. Vou lembrar que seu nome Ă© " + savedName + "."
        : "Certo, " + getEloCoreFirstName_(savedName) + ". Vou lembrar do seu nome nas prĂłximas conversas.";
      return {
        shortAnswer: answer,
        fullAnswer: answer,
        nextAction: "",
        canSave: false,
        sessionTheme: "perfil",
        sessionIntent: "user_name_memory"
      };
    }
    return null;
  }
  function detectUserNameSave_(message) {
    const userNameIntent = detectEloCoreUserNameMemoryIntent_(message);
    if (userNameIntent && userNameIntent.type === "save") {
      return userNameIntent.name || "";
    }
    const clean = sanitizeUserText(message).replace(/[.!?]+$/g, "").trim();
    if (looksLikeQuestionOrRequestForName_(message)) {
      return "";
    }

    const shortSouMatch = clean.match(/^sou\s+(.+)$/i);
    if (shortSouMatch) {
      const shortName = cleanEloCoreUserNameCandidate_(shortSouMatch[1]);
      return isValidExplicitUserName_(shortName) ? shortName : "";
    }

    return "";
  }

  function detectStandaloneNameCapture_(message) {
    return detectUserNameSave_(message);
  }

  function isStandaloneNameCaptureAttempt_(message) {
    const normalized = normalizeWakeCallText(message);
    return /^(meu nome (?:e|Ă©)|eu me chamo|pode me chamar de|me chame de|sou)\s+/.test(normalized);
  }

  function detectEloDemoQuestion_(text) {
    return hasAnyTerm(text, [
      "modo demonstracao",
      "modo demonstraĂ§ĂŁo",
      "demonstrar o elo",
      "mostrar demonstracao",
      "mostrar demonstraĂ§ĂŁo",
      "apresentacao do sistema",
      "apresentaĂ§ĂŁo do sistema",
      "me mostre o que voce faz",
      "me mostre o que vocĂȘ faz",
      "o que voce consegue fazer",
      "o que vocĂȘ consegue fazer",
      "como voce pode ajudar",
      "como vocĂȘ pode ajudar"
    ]);
  }

  function detectGuidedActionType_(text) {
    if (hasAnyTerm(text, ["quero criar um rdo", "quero fazer um rdo", "quero registrar rdo", "criar um rdo"])) {
      return "rdo";
    }
    if (hasAnyTerm(text, ["quero fazer um relatorio", "quero fazer um relatĂłrio", "quero criar um relatorio", "quero criar um relatĂłrio"])) {
      return "relatorio";
    }
    if (hasAnyTerm(text, ["quero lancar material", "quero lanĂ§ar material", "quero registrar material", "quero lancar materiais", "quero lanĂ§ar materiais", "quero lanĂ§ar material", "quero lancar material"])) {
      return "material";
    }
    if (hasAnyTerm(text, ["quero gerar pdf", "quero gerar um pdf", "quero exportar pdf"])) {
      return "pdf";
    }
    if (hasAnyTerm(text, ["quero controlar estoque", "quero testar estoque", "quero usar stock ia"])) {
      return "estoque";
    }
    if (hasAnyTerm(text, ["quero testar o sistema", "sou novo aqui", "sou nova aqui", "por onde comeco", "por onde comeĂ§o"])) {
      return "inicio";
    }
    return "";
  }

  function detectConstructionRecord(message) {
    const clean = sanitizeUserText(message);
    const text = normalizeEloText(clean);
    const productionMatch = text.match(/(?:foram executados|foi executado|fizemos|hoje executamos|executamos)\s+([\d]+(?:[,.]\d+)?)\s*(m2|mÂČ|metros|metro|sacos|un|unidades)?\s+de\s+([a-z0-9\sĂ§ĂŁĂ”ĂĄĂ©Ă­ĂłĂșĂąĂȘĂŽ]+?)(?:\s+e\s+|$)/);
    const materialMatches = [];
    const materialRegex = /(?:usados|usamos|gastamos|foram usados|foi usado)\s+([\d]+(?:[,.]\d+)?)\s+(?:(sacos|saco|kg|m2|mÂČ|un|unidades?)\s+de\s+)?([a-z0-9\sĂ§ĂŁĂ”ĂĄĂ©Ă­ĂłĂșĂąĂȘĂŽ]+?)(?:\s+e\s+|$)/g;
    let match = materialRegex.exec(text);
    while (match) {
      materialMatches.push({
        quantity: match[1],
        unit: match[2] || "",
        name: sanitizeLibraryText(match[3], 80)
      });
      match = materialRegex.exec(text);
    }
    if (!productionMatch && !materialMatches.length) {
      return null;
    }
    return {
      service: productionMatch ? sanitizeLibraryText(productionMatch[3], 80) : "",
      quantity: productionMatch ? productionMatch[1] : "",
      unit: productionMatch ? (productionMatch[2] || "") : "",
      materials: materialMatches
    };
  }

  function classifyEloIntent(message, context) {
    const text = stripEloMentionForIntent_(message);
    const userNameMemory = detectEloCoreUserNameMemoryIntent_(message);
    if (userNameMemory && (userNameMemory.type === "save" || userNameMemory.type === "query")) {
      return "user_name_memory";
    }
    const saveName = detectUserNameSave_(message);
    if (saveName) {
      return "save_user_name";
    }
    if (hasAnyTerm(text, ["voce e humano", "voce esta vivo", "voce sente emocao", "voce sente emocoes", "voce tem consciencia"])) {
      return "elo_limits";
    }
    if (hasAnyTerm(text, ["qual meu nome", "qual e o meu nome", "qual Ă© o meu nome", "como eu me chamo", "voce sabe meu nome", "vocĂȘ sabe meu nome"])) {
      return "user_name_question";
    }
    if (hasAnyTerm(text, ["qual seu nome", "qual e seu nome", "qual Ă© seu nome", "qual o seu nome", "qual e o seu nome", "qual Ă© o seu nome", "qual o nome do elo", "qual e o nome do elo", "qual Ă© o nome do elo", "seu nome e qual", "seu nome Ă© qual", "como voce se chama", "como vocĂȘ se chama", "quem e voce", "quem Ă© vocĂȘ", "quem e o elo", "quem Ă© o elo", "o que e o elo", "o que Ă© o elo"])) {
      return "elo_identity";
    }
    if (detectDayClosingRequest(message)) {
      return "day_closing";
    }
    if (detectDaySummaryRequest(message)) {
      return "day_summary";
    }
    if (detectSocialGreeting(message)) {
      return "greeting";
    }
    if (detectConstructionRecord(message)) {
      return "construction_record";
    }
    if (detectEloDemoQuestion_(text)) {
      return "elo_demo";
    }
    if (detectGuidedActionType_(text)) {
      return "guided_action";
    }
    if (detectSynthesisRequest(message) || detectRecommendationRequest(message)) {
      return "synthesis_recommendation";
    }
    if (hasAnyTerm(text, ["me ajuda", "me ajude", "e agora", "continua", "qual proximo passo", "o que faco"])) {
      return "continuity";
    }
    if (detectProjectAdvisorRequest(message)) {
      return "project_advisor";
    }
    if (buildDecisionMemoryAnswer(message)) {
      return "decision_memory";
    }
    if (detectEloInitiativeOpportunity(message, context)) {
      return "initiative_opportunity";
    }
    if (hasAnyTerm(text, ["o que voce faz", "o que vocĂȘ faz", "suas funcoes", "suas funĂ§Ă”es", "capacidades do elo", "como voce ajuda", "como vocĂȘ ajuda"])) {
      return "capabilities";
    }
    if (detectLogicalReasoningQuestion(message)) {
      return "logical_reasoning";
    }
    if (detectJourneyReportRequest(message)) {
      return "journey_report";
    }
    if (buildTimelineAnswer(message)) {
      return "timeline_question";
    }
    if (detectNarrativeMemoryQuestion(message) || hasAnyTerm(text, ["meus projetos", "linha do tempo", "o que voce lembra", "o que vocĂȘ lembra"])) {
      return "memory_question";
    }
    if (isEloLibraryQuestion(message) || (hasAnyTerm(text, ["o que voce sabe sobre", "o que vocĂȘ sabe sobre"]) && buildEloLibraryAnswer(message))) {
      return "library_question";
    }
    if (hasAnyTerm(text, ["como uso o sistema", "como usar o sistema", "nunca usei", "por onde comeco", "por onde comeĂ§o", "onde cadastro obra", "onde cadastrar obra", "onde cadastro cliente", "como envio para cliente", "como usar obrareport", "como funciona o obrareport", "o que e obrareport", "o que Ă© obrareport"])) {
      return "system_help";
    }
    if (hasAnyTerm(text, ["rdo", "diario de obra", "diario de obras", "diĂĄrio de obra", "diĂĄrio de obras", "servico executado", "serviĂ§o executado", "producao executada", "produĂ§ĂŁo executada"])) {
      return "rdo_help";
    }
    if (hasAnyTerm(text, ["stock ia", "estoque", "almoxarifado", "materiais acabando", "entrada por nota", "saldo de estoque"])) {
      return "stock_help";
    }
    if (hasAnyTerm(text, ["material", "materiais", "consumo", "lancei", "alvenaria", "cimento", "bloco", "areia"])) {
      return "materials_help";
    }
    if (hasAnyTerm(text, ["pdf", "gerar pdf", "exportar pdf"])) {
      return "pdf_help";
    }
    if (hasAnyTerm(text, ["relatorio tecnico", "relatĂłrio tĂ©cnico", "relatorio", "relatĂłrio", "vistoria", "laudo"])) {
      return "report_help";
    }
    if (getConceptResponse(message) || getPhilosophyResponse(message)) {
      return "conceptual_question";
    }
    return "unknown";
  }

